import { createClient } from '@/lib/supabase/server';
import { Video } from '@/types';
import { PlayCircle } from 'lucide-react';
import Link from 'next/link';

export const metadata = {
  title: 'Video Library | Advaitha Yogam',
  description: 'Spiritual discourses, yoga practices, and guided meditations in video format.',
};

export default async function VideosPage() {
  const supabase = await createClient();
  
  const { data: videos, error } = await supabase
    .from('videos')
    .select('*')
    .eq('status', 'published')
    .order('created_at', { ascending: false });

  return (
    <div className="min-h-screen bg-[#FAFAFA] py-20 px-4 sm:px-6 lg:px-8 font-[family-name:var(--font-outfit)]">
      <div className="max-w-7xl mx-auto">
        <div className="text-center mb-16">
          <h1 className="text-4xl md:text-5xl font-bold font-[family-name:var(--font-cormorant)] text-[#2D5A3D] mb-4">
            Video Library
          </h1>
          <p className="text-lg text-gray-600 max-w-2xl mx-auto">
            Immerse yourself in spiritual discourses, guided practices, and profound wisdom from the masters.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {videos?.map((video: Video) => (
            <div key={video.id} className="bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 group border border-gray-100 flex flex-col">
              <a href={video.youtube_url} target="_blank" rel="noreferrer" className="relative block w-full aspect-video bg-gray-100 overflow-hidden">
                {video.thumbnail_url ? (
                  <img 
                    src={video.thumbnail_url} 
                    alt={video.title} 
                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                  />
                ) : (
                  <div className="absolute inset-0 flex items-center justify-center bg-gray-200 text-gray-400">
                    No Thumbnail
                  </div>
                )}
                <div className="absolute inset-0 bg-black/20 group-hover:bg-black/10 transition-colors flex items-center justify-center">
                  <PlayCircle className="text-white/80 group-hover:text-white transition-colors w-16 h-16 drop-shadow-md" />
                </div>
              </a>
              <div className="p-6 flex flex-col flex-1">
                <div className="flex items-center gap-2 mb-3">
                  {video.genre && (
                    <span className="text-xs font-semibold tracking-wider uppercase text-amber-600 bg-amber-50 px-2 py-1 rounded">
                      {video.genre}
                    </span>
                  )}
                  {video.is_own_content && (
                    <span className="text-xs font-semibold tracking-wider uppercase text-emerald-600 bg-emerald-50 px-2 py-1 rounded">
                      Original
                    </span>
                  )}
                </div>
                <h3 className="text-xl font-bold text-gray-900 mb-2 leading-tight">
                  <a href={video.youtube_url} target="_blank" rel="noreferrer" className="hover:text-amber-600 transition-colors">
                    {video.title}
                  </a>
                </h3>
                {video.description && (
                  <p className="text-gray-600 text-sm line-clamp-2 mb-4 flex-1">
                    {video.description}
                  </p>
                )}
                <div className="mt-auto flex items-center justify-between text-xs text-gray-500">
                  <span>{new Date(video.created_at).toLocaleDateString(undefined, { year: 'numeric', month: 'short', day: 'numeric' })}</span>
                </div>
              </div>
            </div>
          ))}
          
          {(!videos || videos.length === 0) && (
            <div className="col-span-full py-20 text-center bg-white rounded-2xl border border-gray-100">
              <p className="text-gray-500 text-lg">No videos available yet. Please check back soon.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
